// Generated by Cypress Author — 2026-05-20
// Covers: Running Tracker onboarding flow (3 steps):
//   Step 1 — Biometrics (field rendering, validation, formula/manual max HR, happy path)
//   Step 2 — Strava Connect (skip flow, connect button)
//   Step 3 — First Goal (no-goal path, yes-goal path with race distance + date)
//   Auth guard — unauthenticated visit redirects to /login
//   (app) layout guard — routes under /main/running/(app)/ require real Supabase session
//
// AUTH STRATEGY:
//   - /main/running/onboarding uses app/main/layout.jsx → requireAuth() → bypass-friendly
//     BUT we also call cy.setupApiAuthCookies() so the API calls in the form work correctly
//   - /main/running/dashboard (and other (app) routes) use (app)/layout.jsx which calls
//     supabase.auth.getUser() directly. We must use cy.setupApiAuthCookies() for a real
//     Supabase session — the bypass cookie alone is NOT sufficient for those routes.

// ---------------------------------------------------------------------------
// Shared helpers
// ---------------------------------------------------------------------------

/**
 * Fills Step 1 (Biometrics) with valid values using placeholder-based selectors.
 * These selectors are interim — id attributes have been requested via Frontend signal.
 */
const fillBiometricsValid = () => {
  // Birth date — use a date ~30 years ago so the formula HR preview shows
  cy.get('input[type="date"]').first().type('1994-06-15')
  // Height
  cy.get('input[placeholder="170"]').type('172')
  // Weight
  cy.get('input[placeholder="65"]').type('68')
  // Resting HR
  cy.get('input[placeholder="55"]').type('58')
  // Max HR mode stays as 'formula' (default) — no extra action needed
}

// ---------------------------------------------------------------------------
// A. Unauthenticated access guard
// ---------------------------------------------------------------------------

describe('Running Onboarding — Auth Guard', () => {
  it('unauthenticated visit to /main/running/onboarding redirects to /login', () => {
    cy.clearAllCookies()
    cy.clearAllLocalStorage()
    cy.visit('/main/running/onboarding', { failOnStatusCode: false })
    cy.url().should('include', '/login')
  })

  it('unauthenticated visit to (app) route /main/running/dashboard redirects to /login', () => {
    cy.clearAllCookies()
    cy.clearAllLocalStorage()
    cy.visit('/main/running/dashboard', { failOnStatusCode: false })
    cy.url().should('include', '/login')
  })
})

// ---------------------------------------------------------------------------
// B. Step 1 — Biometrics form rendering
// ---------------------------------------------------------------------------

describe('Running Onboarding — Step 1 Biometrics (rendering)', () => {
  before(() => {
    // setupApiAuthCookies ensures the real Supabase session cookie is present
    // so API calls from the form work; loginWithBypass handles requireAuth() in main layout
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.loginWithBypass()
    cy.setupApiAuthCookies()
    cy.visit('/main/running/onboarding')
  })

  it('renders the onboarding page heading', () => {
    cy.contains('Welcome to Running Tracker').should('be.visible')
  })

  it('shows step 1 of 3 label', () => {
    cy.contains('Step 1 of 3').should('be.visible')
  })

  it('shows step indicator with Biometrics, Connect Strava, First Goal', () => {
    cy.contains('Biometrics').should('be.visible')
    cy.contains('Connect Strava').should('be.visible')
    cy.contains('First Goal').should('be.visible')
  })

  it('renders the Biometrics form heading', () => {
    cy.contains("Let's set up your biometrics").should('be.visible')
  })

  it('renders Birth date, Height, Weight, Resting HR and Max HR fields', () => {
    cy.get('input[type="date"]').should('exist')
    cy.get('input[placeholder="170"]').should('exist')
    cy.get('input[placeholder="65"]').should('exist')
    cy.get('input[placeholder="55"]').should('exist')
  })

  it('formula mode is selected by default and shows formula label', () => {
    cy.contains('Use formula (220 − age)').should('be.visible')
    cy.contains('Enter manually').should('be.visible')
    // manual input should not exist in formula mode
    cy.get('input[placeholder="185"]').should('not.exist')
  })

  it('shows Continue button', () => {
    cy.contains('button', 'Continue').should('be.visible')
  })

  it('does NOT show a Back button on step 1', () => {
    cy.get('[aria-label="Go back to previous step"]').should('not.exist')
  })
})

