describe('Running Onboarding — Step 1 Biometrics (validation)', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.loginWithBypass()
    cy.setupApiAuthCookies()
    cy.visit('/main/running/onboarding')
  })

  it('shows validation error when birth date is missing → does not advance to step 2', () => {
    // Stub the biometric API to prevent real DB writes during validation tests
    cy.intercept('POST', '/api/running/v1/onboarding/biometric').as('biometricSave')

    cy.get('input[placeholder="170"]').type('172')
    cy.get('input[placeholder="65"]').type('68')
    cy.get('input[placeholder="55"]').type('58')

    cy.contains('button', 'Continue').click()

    // Still on step 1 — birth date error should appear
    cy.contains('Birth date is required').should('be.visible')
    cy.contains('Step 1 of 3').should('be.visible')
  })

  it('shows validation error when height is out of range (99) → does not advance', () => {
    cy.get('input[type="date"]').first().type('1994-06-15')
    cy.get('input[placeholder="170"]').type('99')
    cy.get('input[placeholder="65"]').type('68')
    cy.get('input[placeholder="55"]').type('58')
    cy.contains('button', 'Continue').click()

    cy.contains('Height must be between 100 and 250 cm').should('be.visible')
    cy.contains('Step 1 of 3').should('be.visible')
  })

  it('shows validation error when weight is out of range (25) → does not advance', () => {
    cy.get('input[type="date"]').first().type('1994-06-15')
    cy.get('input[placeholder="170"]').type('172')
    cy.get('input[placeholder="65"]').type('25')
    cy.get('input[placeholder="55"]').type('58')
    cy.contains('button', 'Continue').click()

    cy.contains('Weight must be between 30 and 300 kg').should('be.visible')
    cy.contains('Step 1 of 3').should('be.visible')
  })

  it('shows validation error when resting HR is out of range (130) → does not advance', () => {
    cy.get('input[type="date"]').first().type('1994-06-15')
    cy.get('input[placeholder="170"]').type('172')
    cy.get('input[placeholder="65"]').type('68')
    cy.get('input[placeholder="55"]').type('130')
    cy.contains('button', 'Continue').click()

    cy.contains('Resting HR must be between 30 and 120 bpm').should('be.visible')
    cy.contains('Step 1 of 3').should('be.visible')
  })

  it('shows manual max HR error when mode is manual and field is empty', () => {
    cy.get('input[type="date"]').first().type('1994-06-15')
    cy.get('input[placeholder="170"]').type('172')
    cy.get('input[placeholder="65"]').type('68')
    cy.get('input[placeholder="55"]').type('58')

    // Switch to manual mode
    cy.contains('Enter manually').click()
    cy.get('input[placeholder="185"]').should('be.visible')
    // Leave manual max HR empty and try to submit
    cy.contains('button', 'Continue').click()

    cy.contains('Max HR is required').should('be.visible')
    cy.contains('Step 1 of 3').should('be.visible')
  })

  it('shows manual max HR out-of-range error (50 bpm) → does not advance', () => {
    cy.get('input[type="date"]').first().type('1994-06-15')
    cy.get('input[placeholder="170"]').type('172')
    cy.get('input[placeholder="65"]').type('68')
    cy.get('input[placeholder="55"]').type('58')

    cy.contains('Enter manually').click()
    cy.get('input[placeholder="185"]').type('50')
    cy.contains('button', 'Continue').click()

    cy.contains('Max HR must be between 100 and 250 bpm').should('be.visible')
    cy.contains('Step 1 of 3').should('be.visible')
  })
})

