// ---------------------------------------------------------------------------
// E. Step 1 → Step 2 — Advancing via Continue (happy path, stubbed API)
// ---------------------------------------------------------------------------

describe('Running Onboarding — Step 1 → Step 2 (happy path, stubbed)', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.loginWithBypass()
    cy.setupApiAuthCookies()
    cy.visit('/main/running/onboarding')
  })

  it('fills valid biometrics and advances to Step 2 after API succeeds', () => {
    cy.intercept('POST', '/api/running/v1/onboarding/biometric', {
      statusCode: 200,
      body: { data: { id: 'test-user-id' }, message: 'Biometric data saved' },
    }).as('saveBiometric')

    fillBiometricsValid()
    cy.contains('button', 'Continue').click()

    cy.wait('@saveBiometric').its('response.statusCode').should('eq', 200)

    // Should now be on step 2
    cy.contains('Connect Strava').should('be.visible')
    cy.contains('Step 2 of 3').should('be.visible')
  })

  it('shows root error when biometric API returns 500', () => {
    cy.intercept('POST', '/api/running/v1/onboarding/biometric', {
      statusCode: 500,
      body: { error: 'Internal server error', message: 'Something went wrong' },
    }).as('saveBiometricFail')

    fillBiometricsValid()
    cy.contains('button', 'Continue').click()

    cy.wait('@saveBiometricFail')

    // Root error should appear; stays on step 1
    cy.get('[role="alert"]').should('be.visible')
    cy.contains('Step 1 of 3').should('be.visible')
  })
})

