// ---------------------------------------------------------------------------
// H. Step 3 — First Goal (yes, I have a race)
// ---------------------------------------------------------------------------

describe('Running Onboarding — Step 3 First Goal (yes, I have a race)', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  const advanceToStep3 = () => {
    cy.intercept('POST', '/api/running/v1/onboarding/biometric', {
      statusCode: 200,
      body: { data: {}, message: 'Biometric data saved' },
    }).as('saveBiometric')

    fillBiometricsValid()
    cy.contains('button', 'Continue').click()
    cy.wait('@saveBiometric')
    cy.get('[aria-label="Skip Strava connection for now"]').click()
    cy.contains('Step 3 of 3').should('be.visible')
  }

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.loginWithBypass()
    cy.setupApiAuthCookies()
    cy.visit('/main/running/onboarding')
    advanceToStep3()
    // The radio input is covered by its parent <label> — click the label instead
    cy.contains('label', 'Yes, I have a race').click()
  })

  it('shows goal fields when "Yes, I have a race" is selected', () => {
    cy.get('input[placeholder="e.g. 30"]').should('be.visible')
    cy.contains('5K').should('be.visible')
    cy.contains('10K').should('be.visible')
    cy.contains('Half Marathon').should('be.visible')
    cy.contains('Marathon').should('be.visible')
  })

  it('clicking a quick distance button fills the distance input', () => {
    cy.contains('button', '5K').click()
    cy.get('input[placeholder="e.g. 30"]').should('have.value', '5')
  })

  it('clicking Marathon (exact match) fills 42.195 in distance input', () => {
    // Use exact text regex to avoid matching "Half Marathon" (cy.contains does substring match)
    cy.contains('button', /^Marathon$/).click()
    cy.get('input[placeholder="e.g. 30"]').should('have.value', '42.195')
  })

  it('shows "Save goal & go to dashboard" button when race goal is selected', () => {
    cy.contains('button', 'Save goal & go to dashboard').should('be.visible')
  })

  it('saves goal and redirects to dashboard when valid goal is set', () => {
    cy.intercept('POST', '/api/running/v1/onboarding/complete', {
      statusCode: 200,
      body: { data: {}, message: 'Onboarding complete' },
    }).as('completeOnboarding')

    cy.contains('button', /^Marathon$/).click()

    // Set a race date in the future
    cy.get('input[type="date"]').last().type('2027-04-15')

    cy.contains('button', 'Save goal & go to dashboard').click()

    cy.wait('@completeOnboarding')
      .its('request.body')
      .then((body) => {
        expect(body.goal_type).to.eq('race')
        expect(body.target_distance_m).to.eq(42195)
        expect(body.target_date).to.eq('2027-04-15')
      })

    cy.url().should('include', '/main/running/dashboard')
  })

  it('completes onboarding even if the API returns 500 (goal save failure is non-blocking)', () => {
    cy.intercept('POST', '/api/running/v1/onboarding/complete', {
      statusCode: 500,
      body: { error: 'Internal server error' },
    }).as('completeOnboardingFail')

    // Reset to "No race planned" so "Go to dashboard" button is shown
    cy.contains('label', 'No race planned yet').click()
    cy.contains('button', 'Go to dashboard').click()

    cy.wait('@completeOnboardingFail')
    // Per PRD spec: goal save failure is non-blocking — should still redirect
    cy.url().should('include', '/main/running/dashboard')
  })
})

// ---------------------------------------------------------------------------
// I. (app) layout guard — visiting (app) routes requires real Supabase session
// ---------------------------------------------------------------------------

describe('Running (app) layout — auth guard with real Supabase session', () => {
  it('setupApiAuthCookies provides a real Supabase session for (app) routes', () => {
    // The (app)/layout.jsx calls supabase.auth.getUser() directly (not requireAuth())
    // so it needs a real sb-{projectRef}-auth-token cookie — not just the bypass cookie.
    // setupApiAuthCookies sets exactly that cookie.
    // We stub the rt_users check to avoid needing a real onboarding_complete record.
    cy.setupApiAuthCookies()

    // Intercept the Supabase REST request for rt_users table that (app)/layout.jsx makes
    // after auth succeeds — respond as if onboarding is complete so we reach the page.
    cy.intercept('GET', '**/rest/v1/rt_users*', {
      statusCode: 200,
      body: [{ id: 'test-user-id', onboarding_complete: true }],
    }).as('rtUsersCheck')

    cy.visit('/main/running/dashboard')

    // If the auth guard passes (real session valid), we should NOT be on /login
    // and NOT be redirected to /onboarding.
    cy.url().should('not.include', '/login')
  })
})
